// Extract and validate JavaScript from index.html
const fs = require('fs');
const html = fs.readFileSync('index.html', 'utf8');

// Check file structure
const hasDoctype = html.startsWith('<!DOCTYPE html>');
const hasHtmlClose = html.includes('</html>');
const hasScriptOpen = html.includes('<script>');
const hasScriptClose = html.includes('</script>');
const hasStyleOpen = html.includes('<style>');
const hasStyleClose = html.includes('</style>');

console.log('File Structure Check:');
console.log('- Has DOCTYPE:', hasDoctype);
console.log('- Has </html>:', hasHtmlClose);
console.log('- Has <style>:', hasStyleOpen);
console.log('- Has </style>:', hasStyleClose);
console.log('- Has <script>:', hasScriptOpen);
console.log('- Has </script>:', hasScriptClose);

// Extract JavaScript
const scriptMatch = html.match(/<script>([\s\S]*?)<\/script>/);
if (scriptMatch) {
    const js = scriptMatch[1];
    console.log('\nJavaScript extracted successfully');
    console.log('- JS length:', js.length, 'characters');

    // Check for key components
    console.log('\nKey Components Check:');
    console.log('- Has PUZZLE_LIBRARY:', js.includes('PUZZLE_LIBRARY'));
    console.log('- Has SudokuEngine class:', js.includes('class SudokuEngine'));
    console.log('- Has LocalStorageDB class:', js.includes('class LocalStorageDB'));
    console.log('- Has SudokuUI class:', js.includes('class SudokuUI'));
    console.log('- Has DOMContentLoaded:', js.includes('DOMContentLoaded'));

    // Count puzzles
    const puzzleMatches = js.match(/\{ id: '[^']+', difficulty: '[^']+'/g);
    console.log('\nPuzzle Count:', puzzleMatches ? puzzleMatches.length : 0);

    // Check for easy/medium/hard
    const easyCount = (js.match(/difficulty: 'easy'/g) || []).length;
    const mediumCount = (js.match(/difficulty: 'medium'/g) || []).length;
    const hardCount = (js.match(/difficulty: 'hard'/g) || []).length;
    console.log('- Easy puzzles:', easyCount);
    console.log('- Medium puzzles:', mediumCount);
    console.log('- Hard puzzles:', hardCount);

    console.log('\n✅ All checks passed! File is complete.');
} else {
    console.log('\n❌ Could not extract JavaScript from file');
}
